import React, { useRef, useCallback } from 'react'
import PropTypes from 'prop-types'
import { NoticeLoading } from '@fs/zion-icon'
import { useEvent, useObserver, useUnmountableState } from '@fs/zion-frontend-friends'
import { useTranslation } from 'react-i18next'

function DefaultLoadingContent() {
  const { t } = useTranslation()
  return <NoticeLoading size="sm" aria-label={t('common-ui:loading.ellipsis.label')} />
}

/** This node needs to be removed from the dom
 * and re-added whenever new data is being loaded
 * by the consumer. The reason for this is to cover
 * the case where a consumer adds more nodes above this,
 * but not enough to move this node off-screen.
 * If they don't move it off-screen, the intersectionObserver
 * won't run again. By removing it from the DOM then re-adding it,
 * the IntersectionObserver will get triggered again when it gets
 * added back and still on-screen.
 */
const IntersectionNode = ({ callback, as: TagName = 'div' }) => {
  const domRef = useRef()
  useObserver(domRef, callback)
  return <TagName ref={domRef} />
}

// when this DOM node is visible, trigger the fetchMore callback
export default function InfiniteScroller({ fetchMore, children, as: TagName = 'div', observerNode, ...props }) {
  const [atEnd, setAtEnd] = useUnmountableState(false)
  const [isWaiting, setIsWaiting] = useUnmountableState(false)

  const getMore = useEvent(fetchMore)

  const inViewCallback = useCallback(
    async (entry) => {
      if (!entry.isIntersecting) return

      setIsWaiting(true)
      const moreToGet = await getMore()
      if (!moreToGet) setAtEnd(true)
      setIsWaiting(false)
    },
    [getMore, setAtEnd, setIsWaiting]
  )

  return !atEnd ? (
    <TagName {...props}>
      {!isWaiting && <IntersectionNode callback={inViewCallback} as={observerNode} />}
      {children || <DefaultLoadingContent />}
    </TagName>
  ) : null
}

InfiniteScroller.propTypes = {
  /** What component or dom node to use to wrap the chiildren */
  as: PropTypes.elementType,

  /** What component or dom node to use for the IntersectionObserver */
  observerNode: PropTypes.elementType,

  /**
   * Function that handles fetching more data. It should return a promise that resolves
   * to true if there's more data to fetch, and false if there's no more data.
   *
   * If there is no more data, the loading icon will go away.
   */
  fetchMore: PropTypes.func.isRequired,

  /** The content you wish to show while data is being loaded. Defaults to a NoticeLoading if not provided. */
  children: PropTypes.element,
}
