import React, { lazy, useEffect, Suspense } from 'react'
import { Button, Skeleton, Divider, MenuOverlay, InfiniteScroller, useMenuOverlay } from '@fs/zion-ui'
import { Notice } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { css } from '@linaria/core'
import { Observable } from '@fs/zion-frontend-friends'
import HeaderMenuOverlayFooter from '../HeaderMenuOverlayFooter'
import NotifyListItems from '../NotifyListItems/NotifyListItems'
import HeaderIconButton from '../../../shared/components/HeaderIconButton'
import useThreadSummaries from '../Header2019WithData/ThreadSummariesProvider'

const NotificationListOverlayEmptyState = lazy(() => import('./NotificationListOverlayEmptyState'))

const hasWindow = typeof window !== 'undefined'

const pageUrl = '/notifications'
const pageUrlWithSlash = '/notifications/'
const linkName = 'hdr19_notifications_menu'

const wrapperCSS = css`
  max-height: 364px;
  overflow-x: hidden;
  overflow-y: auto;
  width: 377px;
  padding: 0 12px;
`

export default function NotificationListOverlay({ hasNewNotification, footerButtonText, onOpen }) {
  const { userThreadSummaries, error, loading, loadMoreThreadSummaries, loadInitialContent } = useThreadSummaries()
  const { t } = useTranslation()
  const menuOverlayConfig = useMenuOverlay()
  const [hasBeenOpened, setHasBeenOpened] = React.useState(false)

  // On the first open, load the initial content, set the hasBeenOpened flag to true
  // keeps the empty state from loading before it's opened
  useEffect(() => {
    if (menuOverlayConfig.isOpen) {
      onOpen()

      if (!hasBeenOpened) {
        setHasBeenOpened(true)
        loadInitialContent()
      }
    }
  }, [menuOverlayConfig.isOpen, onOpen, loadInitialContent, hasBeenOpened])

  const notificationListButton = (
    <HeaderIconButton
      {...menuOverlayConfig.menuButtonProps}
      Icon={Notice}
      title={
        hasNewNotification
          ? t('header.notifications.new', 'New notifications available')
          : t('header.notifications', 'Notifications')
      }
      dotted={hasNewNotification}
    />
  )

  const footer = (
    <HeaderMenuOverlayFooter>
      <Button role="menuitem" to={pageUrlWithSlash} linkName={linkName} external>
        {footerButtonText}
      </Button>
    </HeaderMenuOverlayFooter>
  )

  const loadingPlaceholder = (
    <>
      <Skeleton.ListItem hasSecondLine maxWidth={400} />
      <Divider fullWidth />
      <Skeleton.ListItem hasSecondLine maxWidth={400} />
      <Divider fullWidth />
      <Skeleton.ListItem hasSecondLine maxWidth={400} />
      <Divider fullWidth />
      <Skeleton.ListItem hasSecondLine maxWidth={400} />
      <Divider fullWidth />
      <Skeleton.ListItem hasSecondLine maxWidth={400} />
    </>
  )

  if (!hasBeenOpened) {
    return notificationListButton
  }

  if (error) {
    hasWindow && (window.location.href = pageUrlWithSlash)
  }

  let content = (
    <>
      <Observable as="div" className={wrapperCSS}>
        <NotifyListItems userThreadSummaries={userThreadSummaries} pageUrl={pageUrl} linkName={linkName} />
        <InfiniteScroller fetchMore={loadMoreThreadSummaries}>
          <>
            <Skeleton.ListItem hasSecondLine maxWidth={400} />
            <Divider fullWidth />
          </>
        </InfiniteScroller>
      </Observable>
      {footer}
    </>
  )

  if (loading) {
    content = <div className={wrapperCSS}>{loadingPlaceholder}</div>
  }

  if (userThreadSummaries.length === 0) {
    content = (
      <div className={wrapperCSS}>
        <Suspense fallback={loadingPlaceholder}>
          <NotificationListOverlayEmptyState />
        </Suspense>
      </div>
    )
  }

  return (
    <>
      {notificationListButton}
      <MenuOverlay {...menuOverlayConfig}>{content}</MenuOverlay>
    </>
  )
}
