import React, { useState, useEffect } from 'react'
import { Divider, Skeleton } from '@fs/zion-ui'
import NotifyListItem from './NotifyListItem'

export default function NotifyListItems({ userThreadSummaries, ...props }) {
  const [notifyListItems, setNotifyListItems] = useState([])
  const [threadIds, setThreadIds] = useState([])

  useEffect(() => {
    if (userThreadSummaries.length) {
      const newThreadSummaries = filterNewSummaries(threadIds, userThreadSummaries)

      if (newThreadSummaries.length) {
        const newThreadIds = getThreadIdsFromThreadSummaries(newThreadSummaries)
        if (newThreadIds) setThreadIds([...threadIds, ...newThreadIds])

        addNotifyListItems(newThreadSummaries)
      }
    }

    function addNotifyListItems(newThreadSummaries) {
      if (notifyListItems.length) {
        const newNotifyListItems = newThreadSummaries.map((threadSummary) => NotifyItem(threadSummary, props))
        setNotifyListItems((previousNotifyItems) => [...previousNotifyItems, ...newNotifyListItems])
      } else {
        const firstItem = NotifyItem(newThreadSummaries.shift(), props, false)
        const newNotifyListItems = newThreadSummaries.map((threadSummary) => NotifyItem(threadSummary, props))
        setNotifyListItems([firstItem, ...newNotifyListItems])
      }
    }
  }, [userThreadSummaries, notifyListItems.length, threadIds, props])

  return notifyListItems.length
    ? notifyListItems
    : userThreadSummaries.map(({ threadId }, index) => (
        <React.Fragment key={threadId}>
          {index !== 0 && <Divider fullWidth />}
          <Skeleton.ListItem hasSecondLine maxWidth={200} />
        </React.Fragment>
      ))
}

function filterNewSummaries(currentThreadIds, threadSummaries) {
  return Array.from(new Set(threadSummaries.filter(({ threadId }) => !currentThreadIds.includes(threadId))))
}

function getThreadIdsFromThreadSummaries(threadSummaries) {
  return threadSummaries.map(({ threadId }) => threadId)
}

function NotifyItem(threadSummary, props, useDivider = true) {
  const { threadId } = threadSummary
  return (
    <React.Fragment key={threadId}>
      {useDivider && <Divider fullWidth />}
      {NotifyListItemWrapper(threadSummary, props)}
    </React.Fragment>
  )
}

function NotifyListItemWrapper(threadSummary, props) {
  return <NotifyListItem threadSummary={threadSummary} {...props} />
}
