import React from 'react'
import { ListItem, Ellipsis, Skeleton } from '@fs/zion-ui'
import { isThisWeek, isThisYear } from '@fs/zion-locale/date-fns/'
import { intlFormat } from '@fs/zion-locale'

const unread = 'UNREAD'

export default function NotifyListItem({ threadSummary, pageUrl, ...rest }) {
  const { threadId, about, subject, userThreadState, lastModifiedTime } = threadSummary

  return about ? (
    <ListItem
      primaryText={<Ellipsis>{about}</Ellipsis>}
      secondaryText={<Ellipsis>{subject}</Ellipsis>}
      endElement={<ListItem.MetaText text={formatDateString(new Date(lastModifiedTime))} />}
      emphasized={userThreadState === unread}
      to={`${pageUrl}/?thread=${threadId}`}
      {...rest}
      external
    />
  ) : (
    <Skeleton.ListItem hasSecondLine maxWidth={200} />
  )
}

function formatDateString(date) {
  if (isThisWeek(date)) {
    // returns three letter day of the week
    return intlFormat(date, { weekday: 'short' })
  }

  if (isThisYear(date)) {
    // returns numerical day and three letter abbreviated month
    return intlFormat(date, { day: 'numeric', month: 'short' })
  }

  // returns numerical day and three letter abbreviated month and year
  return intlFormat(date, { day: 'numeric', month: 'short', year: 'numeric' })
}
